from flask import Flask, send_file, abort, current_app
from werkzeug.exceptions import NotFound
from pathlib import Path
import os
import re

app = Flask(__name__)

INVOICE_STORAGE_DIR = os.environ.get("INVOICE_STORAGE_DIR", "./invoices")


def get_invoice_pdf_path(invoice_id: int) -> Path:
    base = Path(INVOICE_STORAGE_DIR).resolve()
    pdf_path = (base / f"invoice_{invoice_id}.pdf").resolve()
    if not str(pdf_path).startswith(str(base) + os.sep) and str(pdf_path) != str(base):
        raise NotFound()
    return pdf_path


@app.get("/api/invoices/<invoice_id>/download")
def download_invoice(invoice_id):
    if not re.fullmatch(r"\d+", str(invoice_id)):
        abort(404)

    inv_id = int(invoice_id)
    if inv_id <= 0:
        abort(404)

    pdf_path = get_invoice_pdf_path(inv_id)
    if not pdf_path.is_file():
        abort(404)

    return send_file(
        pdf_path,
        mimetype="application/pdf",
        as_attachment=True,
        download_name=f"invoice_{inv_id}.pdf",
        conditional=True,
        max_age=0,
        etag=True,
        last_modified=pdf_path.stat().st_mtime,
    )


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", "5000")))